import { existsSync, readFileSync } from 'fs'
import { readdir, readFile, stat } from 'fs/promises'
import { join, isAbsolute } from 'path'
import { homedir } from 'os'
// eslint-disable-next-line @typescript-eslint/no-var-requires
const Database = require('better-sqlite3')

export interface DiscoveredSession {
  sessionId: string
  slug: string
  lastModified: number
  cwd: string
  fileSize: number
}

export type SessionBackend = 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'

// Message types that indicate actual conversation content (not just summaries)
const CONVERSATION_TYPES = ['user', 'assistant']
const OPENCODE_CONFIG_NAME = '.opencode.json'

function encodeProjectPath(projectPath: string): string {
  // Claude encodes paths by:
  // 1. Removing trailing slashes/backslashes
  // 2. Replacing / and \ with -
  // 3. Replacing _ with -
  // 4. Replacing spaces with -
  // 5. Replacing : with - (Windows drive letters)
  // 6. Replacing dots with dashes (e.g. .config -> -config)
  // /home/user/my_project/ becomes -home-user-my-project
  // /home/user/.config/app becomes -home-user--config-app
  // C:\Users\bob\project becomes -C-Users-bob-project
  return projectPath
    .replace(/[/\\]+$/, '')  // Remove trailing slashes/backslashes
    .replace(/[/\\]/g, '-')  // Replace / and \ with -
    .replace(/:/g, '-')      // Replace : with - (Windows drive letters)
    .replace(/_/g, '-')      // Replace _ with -
    .replace(/ /g, '-')      // Replace spaces with -
    .replace(/\./g, '-')     // Replace dots with dashes
}

function expandHomePath(targetPath: string): string {
  if (targetPath === '~') {
    return homedir()
  }
  if (targetPath.startsWith('~/') || targetPath.startsWith('~\\')) {
    return join(homedir(), targetPath.slice(2))
  }
  return targetPath
}

function loadOpenCodeConfig(projectPath: string): { data?: { directory?: string } } | null {
  const home = homedir()
  const xdgConfig = process.env.XDG_CONFIG_HOME
  const candidatePaths = [
    join(projectPath, OPENCODE_CONFIG_NAME),
    ...(xdgConfig ? [join(xdgConfig, 'opencode', OPENCODE_CONFIG_NAME)] : []),
    join(home, '.config', 'opencode', OPENCODE_CONFIG_NAME),
    join(home, OPENCODE_CONFIG_NAME)
  ]

  for (const configPath of candidatePaths) {
    if (!existsSync(configPath)) continue
    try {
      const content = readFileSync(configPath, 'utf-8')
      return JSON.parse(content)
    } catch (e) {
      console.error('Failed to parse OpenCode config:', e)
    }
  }

  return null
}

function resolveOpenCodeDataDir(projectPath: string): string {
  const config = loadOpenCodeConfig(projectPath)
  const configured = config?.data?.directory?.trim()
  const dataDir = configured && configured.length > 0 ? configured : '.opencode'
  const expanded = expandHomePath(dataDir)
  return isAbsolute(expanded) ? expanded : join(projectPath, expanded)
}

async function discoverClaudeSessions(projectPath: string): Promise<DiscoveredSession[]> {
  const claudeDir = join(homedir(), '.claude', 'projects')
  const encodedPath = encodeProjectPath(projectPath)
  const projectSessionsDir = join(claudeDir, encodedPath)

  if (!existsSync(projectSessionsDir)) {
    return []
  }

  const sessions: DiscoveredSession[] = []

  try {
    const files = await readdir(projectSessionsDir)

    // Process files in parallel for better performance
    const results = await Promise.all(
      files
        .filter(file => file.endsWith('.jsonl') && !file.startsWith('agent-'))
        .map(async (file) => {
          const sessionId = file.replace('.jsonl', '')
          const filePath = join(projectSessionsDir, file)

          try {
            const fileStat = await stat(filePath)
            const content = await readFile(filePath, 'utf-8')
            const lines = content.split('\n').filter(line => line.trim())

            // Look for slug and check if session has actual conversation
            let slug = sessionId.slice(0, 8)
            let cwd = projectPath
            let hasConversation = false

            for (const line of lines) {
              try {
                const data = JSON.parse(line)
                if (data.slug) slug = data.slug
                if (data.cwd) cwd = data.cwd
                if (data.type && CONVERSATION_TYPES.includes(data.type)) {
                  hasConversation = true
                }
              } catch {
                // Skip non-JSON lines
              }
            }

            if (!hasConversation) {
              return null
            }

            return {
              sessionId,
              slug,
              lastModified: fileStat.mtimeMs,
              cwd,
              fileSize: fileStat.size
            }
          } catch (e) {
            console.error(`Failed to parse session ${file}:`, e)
            return null
          }
        })
    )

    // Filter out nulls and add to sessions
    for (const result of results) {
      if (result) sessions.push(result)
    }
  } catch (e) {
    console.error('Failed to read sessions directory:', e)
  }

  // Sort by most recent first
  sessions.sort((a, b) => b.lastModified - a.lastModified)

  return sessions
}

function discoverOpenCodeSessions(projectPath: string): DiscoveredSession[] {
  const dataDir = resolveOpenCodeDataDir(projectPath)
  const dbPath = join(dataDir, 'opencode.db')

  if (!existsSync(dbPath)) {
    return []
  }

  try {
    const db = new Database(dbPath, { readonly: true, fileMustExist: true })
    const rows = db.prepare(`
      SELECT id, title, updated_at, created_at, message_count
      FROM sessions
      WHERE parent_session_id IS NULL
      ORDER BY updated_at DESC
    `).all() as Array<{ id: string; title: string | null; updated_at: number; created_at: number; message_count: number }>
    db.close()

    return rows
      .filter(row => (row.message_count ?? 0) > 0)
      .map(row => {
        const lastModifiedSeconds = row.updated_at || row.created_at || 0
        return {
          sessionId: row.id,
          slug: (row.title && row.title.trim()) || row.id.slice(0, 8),
          lastModified: Number(lastModifiedSeconds) * 1000,
          cwd: projectPath,
          fileSize: 0
        }
      })
  } catch (e) {
    console.error('Failed to read OpenCode sessions:', e)
    return []
  }
}

export async function discoverSessions(projectPath: string, backend: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' = 'claude'): Promise<DiscoveredSession[]> {
  if (backend === 'opencode') {
    return discoverOpenCodeSessions(projectPath)
  }
  return discoverClaudeSessions(projectPath)
}

import { app } from 'electron'
import { existsSync, mkdirSync, readFileSync, writeFileSync, renameSync, statSync } from 'fs'
import { join } from 'path'
import { syncMetaProjects } from './meta-project-sync'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number  // Port for HTTP API to send prompts to terminal
  apiAutoStart?: boolean  // Whether to auto-start API when session opens (default: false)
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'  // How API requests handle sessions
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'  // Model for API-triggered sessions
  autoAcceptTools?: string[]  // Per-project tool patterns to auto-accept
  permissionMode?: string     // Per-project permission mode
  color?: string              // Project color for visual identification
  ttsVoice?: string           // Per-project TTS voice (overrides global)
  ttsEngine?: 'piper' | 'xtts'  // Per-project TTS engine
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' // Per-project backend (overrides global)
  categoryId?: string         // Category this project belongs to
  order?: number              // Order within category or uncategorized list
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

export interface TileLayout {
  id: string
  tabIds: string[]
  activeTabId: string
  x: number
  y: number
  width: number
  height: number
}

export interface Workspace {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  viewMode?: 'tabs' | 'tiled'
  tileLayout?: TileLayout[]
  categories?: ProjectCategory[]
}

export interface WindowBounds {
  x: number
  y: number
  width: number
  height: number
}

export interface ThemeCustomization {
  accentColor: string | null
  backgroundColor: string | null
  textColor: string | null
  terminalColors: {
    black?: string
    red?: string
    green?: string
    yellow?: string
    blue?: string
    magenta?: string
    cyan?: string
    white?: string
  } | null
}

export interface Settings {
  defaultProjectDir: string
  theme: string
  themeCustomization?: ThemeCustomization | null
  voiceOutputEnabled?: boolean
  voiceVolume?: number
  voiceSpeed?: number
  voiceSkipOnNew?: boolean
  voiceSilenceThreshold?: number
  autoAcceptTools?: string[]
  permissionMode?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}


interface StoredData {
  workspace: Workspace
  windowBounds?: WindowBounds
  settings?: Settings
}

export class SessionStore {
  private configPath: string
  private backupPath: string
  private data: StoredData

  constructor() {
    const configDir = join(app.getPath('userData'), 'config')
    if (!existsSync(configDir)) {
      mkdirSync(configDir, { recursive: true })
    }
    this.configPath = join(configDir, 'workspace.json')
    this.backupPath = join(configDir, 'workspace.json.backup')
    this.data = this.load()
  }

  private loadFile(path: string): StoredData | null {
    try {
      if (!existsSync(path)) return null
      const stat = statSync(path)
      if (stat.size === 0) return null
      const content = readFileSync(path, 'utf-8')
      const data = JSON.parse(content)
      if (!data?.workspace) return null
      return data
    } catch (e) {
      console.error(`[SessionStore] Failed to load ${path}:`, e)
      return null
    }
  }

  private load(): StoredData {
    // Try main file first
    const main = this.loadFile(this.configPath)
    if (main && (main.workspace.projects?.length || 0) > 0) {
      return main
    }

    // Main file is empty/corrupt/missing — try backup
    const backup = this.loadFile(this.backupPath)
    if (backup && (backup.workspace.projects?.length || 0) > 0) {
      console.log('[SessionStore] Main config empty/corrupt, restored from backup (' +
        backup.workspace.projects.length + ' projects)')
      // Restore backup as main file immediately
      try {
        writeFileSync(this.configPath, JSON.stringify(backup, null, 2))
      } catch (e) {
        console.error('[SessionStore] Failed to restore backup to main:', e)
      }
      return backup
    }

    // If main loaded but had 0 projects (valid empty state), use it
    if (main) return main

    return {
      workspace: {
        projects: [],
        openTabs: [],
        activeTabId: null
      }
    }
  }

  private save(): void {
    try {
      const json = JSON.stringify(this.data, null, 2)

      // Validate we can parse what we're about to write
      JSON.parse(json)

      // Back up existing file before overwriting (if it has content)
      if (existsSync(this.configPath)) {
        try {
          const stat = statSync(this.configPath)
          if (stat.size > 0) {
            // Only update backup if existing file is valid and has projects
            const existing = this.loadFile(this.configPath)
            if (existing && (existing.workspace.projects?.length || 0) > 0) {
              writeFileSync(this.backupPath, readFileSync(this.configPath))
            }
          }
        } catch (e) {
          console.error('[SessionStore] Failed to update backup:', e)
        }
      }

      // Atomic write: write to temp file, then rename
      const tmpPath = this.configPath + '.tmp'
      writeFileSync(tmpPath, json)

      // Verify the temp file was written completely
      const written = readFileSync(tmpPath, 'utf-8')
      JSON.parse(written) // throws if truncated/corrupt

      renameSync(tmpPath, this.configPath)
    } catch (e) {
      console.error('[SessionStore] Failed to save workspace:', e)
    }
  }

  getWorkspace(): Workspace {
    return this.data.workspace
  }

  // Reload workspace from disk (useful when file was modified externally)
  reloadFromDisk(): void {
    console.log('[SessionStore] Reloading workspace from disk')
    this.data = this.load()
    console.log('[SessionStore] Reloaded, projects:', this.data.workspace?.projects?.length || 0)
  }

  saveWorkspace(workspace: Workspace): void {
    // Protect against overwriting populated workspace with empty one
    const incomingProjects = workspace?.projects?.length || 0
    const currentProjects = this.data.workspace?.projects?.length || 0
    if (incomingProjects === 0 && currentProjects > 0) {
      console.log('[SessionStore] Rejected empty workspace save - current has', currentProjects, 'projects')
      return
    }
    this.data.workspace = workspace
    this.save()
    syncMetaProjects(workspace)
  }

  getWindowBounds(): WindowBounds | undefined {
    return this.data.windowBounds
  }

  saveWindowBounds(bounds: WindowBounds): void {
    this.data.windowBounds = bounds
    this.save()
  }

  getSettings(): Settings {
    return this.data.settings ?? { defaultProjectDir: '', theme: 'default', backend: 'default' }
  }

  saveSettings(settings: Settings): void {
    this.data.settings = settings
    this.save()
  }
}

